import React, { useState } from "react";
import { Imgdb, Namedb } from "../components/firebase_setup";
import { v4 } from "uuid";

function Home(){

    const [Txt, setTxt] = useState("");
    const [img, setimg] = useState("");


    const handleUpload=(e) =>{
        console.log(e.target.files[0]);
    }


    const handleLogout =()=>{
        localStorage.clear()
        window.location.reload()
    }


    return(
        <div>
            <h1>This is a placeholder Homepage for Catsa!!!!</h1>
            <section className="upload">
                <input className="textbox" onChange={(e)=>setTxt(e.target.value)}/>
                <input className="ProfilePic" onChange={(e)=>handleUpload(e)} />
            </section>
            <button onClick={handleLogout}>Logout</button>
        </div>
    );
}

export default Home;
